import { Pool } from 'pg';

const pool = new Pool({
  connectionString: process.env.DATABASE_URL,
  max: 20,
  idleTimeoutMillis: 30000,
  connectionTimeoutMillis: 2000,
});

export const db = {
  query: (sql: string, params?: unknown[]) => pool.query(sql, params),
  getClient: () => pool.connect(),
  end: () => pool.end(),
};

